			visited[i] = true
			visited[j] = true
		}
		if canSort {
			return k
		}
	}
	return 0
}

func findIndex(nums []int64, target int64, visited []bool) int {
	for i := 0; i < len(nums); i++ {
		if !visited[i] && nums[i] == target {
			return i
		}
	}
	return -1
}
