func solve(nums []int64) int64 {
	n := len(nums)
	sort.Ints(nums)

	// Check if the array is already sorted
	if nums[0] == 0 && nums[n-1] == int64(n-1) {
		return 0
	}

	// Try all possible k values from 0 to n-1
	for k := int64(n - 1); k >= 0; k-- {
		// Create a copy of the array to perform swaps
		arr := make([]int64, n)
		copy(arr, nums)

		// Try to sort the array using swaps with AND equal to k
		visited := make([]bool, n)
		for i := 0; i < n; i++ {
			if visited[i] {
				continue
			}
			// Find the smallest number in the current group
			minVal := arr[i]
			minIdx := i
			for j := i + 1; j < n; j++ {
				if !visited[j] && (arr[j] & k) == k && arr[j] < minVal {
					minVal = arr[j]
					minIdx = j
				}
			}
			// If a valid swap is found, swap and mark as visited
			if minIdx != i {
				arr[i], arr[minIdx] = arr[minIdx], arr[i]
				visited[minIdx] = true
			}
		}

		// Check if the array is sorted
		isSorted := true
		for i := 0; i < n-1; i++ {
			if arr[i] > arr[i+1] {
				isSorted = false
				break
			}
		}

		if isSorted {
			return k
		}
	}

	return 0
}
